import React, { useEffect, useMemo, useState } from 'react';
import { motion, useAnimationControls } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { useWorkflow } from '../store/workflowContext';

const TYPE_OPTIONS = [
  { key: 'hybrid', title: 'Hybrid Approach', desc: 'Serif body + sans headings', badge: 'AI Pick' },
  { key: 'serif',  title: 'Serif Fonts',     desc: 'Classic elegance for literary/traditional genres' },
  { key: 'sans',   title: 'Sans-Serif Fonts',desc: 'Modern appeal for contemporary/technical content' },
];

const LAYOUT_OPTIONS = [
  { key: 'standard', title: 'Standard', desc: 'Balanced composition for broad appeal', badge: 'AI Pick' },
  { key: 'spacious', title: 'Spacious', desc: 'More white space and enhanced readability' },
  { key: 'compact',  title: 'Compact',  desc: 'Efficient space utilization while readable' },
];

const TRIM_OPTIONS = [
  { key: '5.5x8.5', title: '5.5" × 8.5"', desc: 'Versatile format; great for mid-length books', badge: 'AI Pick' },
  { key: '5x8',     title: '5" × 8"',     desc: 'Compact; romance, YA, poetry, shorter works' },
  { key: '6x9',     title: '6" × 9"',     desc: 'Trade paperback; novels and longer works' },
];

// helper to extract a short snippet from uploaded text
const toSnippet = (text, chars = 140) => {
  if (!text) return 'Add a .txt/.md file to see styled examples from your manuscript.';
  const clean = text.replace(/\s+/g, ' ').trim();
  return clean.length <= chars ? clean : clean.slice(0, chars).trim() + '…';
};

export default function DesignStep() {
  const { design, setDesign, manuscriptFiles, primaryFileId } = useWorkflow();
  const [phase, setPhase] = useState(design.analyzed ? 'recommend' : 'analyzing');
  const nav = useNavigate();

  // resolve main file + snippet for all examples
  const mainFile = useMemo(() => {
    const byId = manuscriptFiles.find((f) => f.id === primaryFileId);
    if (byId) return byId;
    const main = manuscriptFiles.find((f) => f.fileType === 'Main Manuscript' && f.status === 'done');
    if (main) return main;
    return manuscriptFiles.find((f) => f.status === 'done') || null;
  }, [manuscriptFiles, primaryFileId]);

  const snippet = useMemo(() => toSnippet(mainFile?.textContent, 180), [mainFile]);

  // animated “analyzing” stripe
  const controls = useAnimationControls();
  useEffect(() => {
    if (phase !== 'analyzing') return;
    let mounted = true;
    const loop = async () => {
      while (mounted) {
        await controls.start({ x: ['-60%', '120%'], transition: { duration: 1.2, ease: 'linear' } });
        await controls.set({ x: '-60%' });
      }
    };
    loop();
    const t = setTimeout(() => {
      setDesign((d) => ({ ...d, analyzed: true, typography: d.typography ?? 'hybrid' }));
      setPhase('recommend');
    }, 1200);
    return () => { mounted = false; clearTimeout(t); };
  }, [phase, controls, setDesign]);

  // saving effect → route to preview
  useEffect(() => {
    if (!design.saving) return;
    if (design.saveProgress >= 100) return;
    const id = setInterval(() => {
      setDesign((d) => ({ ...d, saveProgress: Math.min(100, d.saveProgress + Math.floor(12 + Math.random() * 18)) }));
    }, 220);
    return () => clearInterval(id);
  }, [design.saving, design.saveProgress, setDesign]);

  useEffect(() => {
    if (design.saving && design.saveProgress >= 100) {
      setDesign((d) => ({ ...d, saving: false, saved: true }));
      nav('/workflow/preview');
    }
  }, [design.saving, design.saveProgress, setDesign, nav]);

  const selectTypography = (key) => setDesign((d) => ({ ...d, typography: key, layout: null, trim: null, stage: 'typography', saved: false }));
  const selectLayout     = (key) => setDesign((d) => ({ ...d, layout: key, saved: false }));
  const selectTrim       = (key) => setDesign((d) => ({ ...d, trim: key, saved: false }));

  if (phase === 'analyzing') {
    return (
      <div className="bg-white rounded-2xl shadow-sm p-10 flex flex-col items-center">
        <div className="text-2xl font-semibold text-slate-900 mb-2">Analyzing your book, one moment…</div>
        <div className="text-slate-500 mb-6">We’re reviewing content to recommend typography, layout, and trim.</div>
        <div className="w-full max-w-xl h-2 bg-slate-200 rounded-full overflow-hidden relative">
          <motion.div
            animate={controls}
            className="absolute top-0 left-0 h-2 w-1/2 rounded-full"
            style={{ background: 'linear-gradient(90deg, #93c5fd 0%, #3b82f6 100%)' }}
          />
        </div>
      </div>
    );
  }

  // live preview classes
  const ty = design.typography || 'hybrid';
  const layout = design.layout || 'standard';
  const trim = (design.trim || '5.5x8.5').replace('x', '×');

  const headingClass = ty === 'serif' ? 'font-serif' : 'font-sans';
  const bodyClass    = ty === 'serif' ? 'font-serif' : ty === 'sans' ? 'font-sans' : 'font-serif';
  const subheadClass = ty === 'hybrid' ? 'font-sans text-slate-500' : `${headingClass} text-slate-500`;
  const layoutBodyClass =
    layout === 'spacious' ? 'text-[17px] leading-8'
    : layout === 'compact' ? 'text-[15px] leading-6'
    : 'text-base leading-7';

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      {/* LEFT: options fed by uploaded snippet */}
      <div className="space-y-6">
        {/* Typography */}
        {design.stage === 'typography' && (
          <section className="space-y-4">
            <h3 className="text-2xl font-semibold">Typography</h3>
            <div className="border rounded-xl p-4 bg-blue-50 border-blue-200">
              <div className="text-sm font-semibold text-blue-700 mb-1">✨ AI Recommendation</div>
              <div className="text-slate-600 text-sm">
                <span className="font-medium">Why hybrid:</span> Serif body + sans headings offers flexible, readable composition.
              </div>
            </div>

            {TYPE_OPTIONS.map((opt) => {
              const active = design.typography === opt.key;
              // per-option styling
              const h = opt.key === 'serif' ? 'font-serif' : 'font-sans';
              const b = opt.key === 'serif' ? 'font-serif' : opt.key === 'sans' ? 'font-sans' : 'font-serif';
              return (
                <button
                  key={opt.key}
                  type="button"
                  onClick={() => selectTypography(opt.key)}
                  className={`w-full text-left border rounded-xl p-4 bg-white hover:bg-slate-50 transition ${
                    active ? 'ring-2 ring-blue-500 border-blue-300' : 'border-slate-200'
                  }`}
                >
                  <div className="flex items-start justify-between">
                    <div>
                      <div className="flex items-center gap-2">
                        <span className={`inline-flex items-center justify-center w-4 h-4 rounded-full border ${
                          active ? 'bg-blue-600 border-blue-600' : 'border-slate-400'}`}>
                          {active && <span className="w-1.5 h-1.5 bg-white rounded-full" />}
                        </span>
                        <div className="font-semibold">{opt.title}</div>
                        {opt.badge && (
                          <span className="ml-2 text-xs px-2 py-0.5 rounded-full bg-blue-50 text-blue-700 border border-blue-200">
                            {opt.badge}
                          </span>
                        )}
                      </div>
                      <div className="text-sm text-slate-600 mt-1">{opt.desc}</div>
                    </div>
                  </div>
                  <div className={`mt-3 text-slate-800 ${b}`}>
                    {snippet}
                  </div>
                </button>
              );
            })}
          </section>
        )}

        {/* Layout */}
        {design.stage === 'layout' && (
          <section className="space-y-4">
            <h3 className="text-2xl font-semibold">Layout Density</h3>
            <div className="border rounded-xl p-4 bg-blue-50 border-blue-200">
              <div className="text-sm font-semibold text-blue-700 mb-1">✨ AI Recommendation</div>
              <div className="text-slate-600 text-sm">
                <span className="font-medium">Why standard:</span> Balanced composition with strong readability.
              </div>
            </div>

            {LAYOUT_OPTIONS.map((opt) => {
              const active = design.layout === opt.key;
              const cls =
                opt.key === 'spacious' ? 'text-[17px] leading-8' :
                opt.key === 'compact'  ? 'text-[15px] leading-6' :
                'text-base leading-7';

              return (
                <button
                  key={opt.key}
                  type="button"
                  onClick={() => selectLayout(opt.key)}
                  className={`w-full text-left border rounded-xl p-4 bg-white hover:bg-slate-50 transition ${
                    active ? 'ring-2 ring-blue-500 border-blue-300' : 'border-slate-200'
                  }`}
                >
                  <div className="flex items-start justify-between">
                    <div>
                      <div className="flex items-center gap-2">
                        <span className={`inline-flex items-center justify-center w-4 h-4 rounded-full border ${
                          active ? 'bg-blue-600 border-blue-600' : 'border-slate-400'}`}>
                          {active && <span className="w-1.5 h-1.5 bg-white rounded-full" />}
                        </span>
                        <div className="font-semibold">{opt.title}</div>
                        {opt.badge && (
                          <span className="ml-2 text-xs px-2 py-0.5 rounded-full bg-blue-50 text-blue-700 border border-blue-200">
                            {opt.badge}
                          </span>
                        )}
                      </div>
                      <div className="text-sm text-slate-600 mt-1">{opt.desc}</div>
                    </div>
                  </div>
                  <div className={`mt-3 text-slate-800 ${bodyClass} ${cls}`}>
                    {snippet}
                  </div>
                </button>
              );
            })}
          </section>
        )}

        {/* Trim */}
        {design.stage === 'trim' && (
          <section className="space-y-4">
            <h3 className="text-2xl font-semibold">Trim Size</h3>
            <div className="border rounded-xl p-4 bg-blue-50 border-blue-200">
              <div className="text-sm font-semibold text-blue-700 mb-1">✨ AI Recommendation</div>
              <div className="text-slate-600 text-sm">
                <span className="font-medium">Why 5.5×8.5:</span> Versatile format that works well for mid-length books.
              </div>
            </div>

            {TRIM_OPTIONS.map((opt) => {
              const active = design.trim === opt.key;
              return (
                <button
                  key={opt.key}
                  type="button"
                  onClick={() => selectTrim(opt.key)}
                  className={`w-full text-left border rounded-xl p-4 bg-white hover:bg-slate-50 transition ${
                    active ? 'ring-2 ring-blue-500 border-blue-300' : 'border-slate-200'
                  }`}
                >
                  <div className="flex items-start justify-between">
                    <div>
                      <div className="flex items-center gap-2">
                        <span className={`inline-flex items-center justify-center w-4 h-4 rounded-full border ${
                          active ? 'bg-blue-600 border-blue-600' : 'border-slate-400'}`}>
                          {active && <span className="w-1.5 h-1.5 bg-white rounded-full" />}
                        </span>
                        <div className="font-semibold">{opt.title}</div>
                        {opt.badge && (
                          <span className="ml-2 text-xs px-2 py-0.5 rounded-full bg-blue-50 text-blue-700 border border-blue-200">
                            {opt.badge}
                          </span>
                        )}
                      </div>
                      <div className="text-sm text-slate-600 mt-1">{opt.desc}</div>
                    </div>
                  </div>
                  <div className={`mt-3 text-slate-800 ${bodyClass} ${layoutBodyClass}`}>
                    {snippet}
                  </div>
                </button>
              );
            })}
          </section>
        )}

        {/* Summary */}
        {design.stage === 'summary' && (
          <section className="space-y-4">
            <h3 className="text-2xl font-semibold">Design Summary</h3>

            <div className="border rounded-xl p-4 bg-white">
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                  <div className="text-xs uppercase text-slate-500 mb-1">Typography</div>
                  <div className="font-medium capitalize">{design.typography || '-'}</div>
                </div>
                <div>
                  <div className="text-xs uppercase text-slate-500 mb-1">Layout</div>
                  <div className="font-medium capitalize">{design.layout || '-'}</div>
                </div>
                <div>
                  <div className="text-xs uppercase text-slate-500 mb-1">Trim</div>
                  <div className="font-medium">{(design.trim || '—').replace('x', '×')}"</div>
                </div>
              </div>

              {/* Example from the uploaded text styled with current selections */}
              <div className="mt-4 border rounded-lg p-3 bg-slate-50">
                <div className={`text-slate-800 ${bodyClass} ${layoutBodyClass}`}>
                  {snippet}
                </div>
              </div>

              {design.saving && (
                <div className="mt-6">
                  <div className="text-sm text-slate-600 mb-1">Saving your design… {design.saveProgress}%</div>
                  <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                    <div className="h-2 bg-blue-600 transition-all" style={{ width: `${design.saveProgress}%` }} />
                  </div>
                </div>
              )}
            </div>
          </section>
        )}
      </div>

      {/* RIGHT: live preview */}
      <div className="bg-white rounded-2xl p-6 shadow-sm">
        <div className="text-sm text-slate-500 mb-2">Live Preview – {trim}" Format</div>
        <div className="border rounded-xl p-6 shadow-sm">
          <h2 className={`text-3xl font-bold mb-2 ${headingClass}`}>Chapter One</h2>
          <h3 className={`text-xl mb-4 ${subheadClass}`}>The Beginning</h3>
          <p className={`mb-3 ${bodyClass} ${layoutBodyClass}`}>{snippet}</p>
          <p className={`mb-3 ${bodyClass} ${layoutBodyClass}`}>{snippet}</p>
          <div className="mt-6 text-xs text-slate-500 grid grid-cols-3 gap-2">
            <div>Typography <span className="font-medium capitalize">{ty}</span></div>
            <div>Layout <span className="font-medium capitalize">{layout}</span></div>
            <div>Size <span className="font-medium">{trim}"</span></div>
          </div>
        </div>
      </div>
    </div>
  );
}
